INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0001-0000-0000-000000000000', '15139528-33df-4856-94bb-dff559fa6688', 'text', '{"html":"<h3>What a Total Station Is</h3><p>A <strong>total station</strong> is a single instrument that combines an <strong>electronic theodolite</strong> (for measuring horizontal and vertical/zenith angles), an <strong>electronic distance meter (EDM)</strong> (for measuring slope distance to a reflector or a surface), and an <strong>onboard microprocessor</strong> that combines those raw observations into coordinates in real time. It typically writes results to an internal memory or an external <strong>data collector</strong>. Because one instrument captures angle <em>and</em> distance to a point from one setup, a surveyor can locate features and corners by <strong>radial</strong> observation rather than the chained-distance-and-turned-angle routine of older theodolite-and-tape work.</p><p>The major external parts are the <strong>telescope</strong> (with crosshairs/reticle), the <strong>standards</strong> carrying the horizontal (trunnion) axis, the <strong>horizontal and vertical circles</strong> read electronically, the <strong>tribrach</strong> with leveling foot screws and an <strong>optical or laser plummet</strong>, and the <strong>keyboard/display</strong>. Internally, electronic angle encoders and the EDM emitter/receiver do the measuring. Understanding which part defines which axis is the key to understanding setup, calibration, and error.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0001-0000-0000-000000000001', '15139528-33df-4856-94bb-dff559fa6688', 'table', '{"headers":["Component","Function"],"rows":[["Telescope / reticle","Sights the target; line of sight defines the collimation axis"],["Horizontal circle (encoder)","Reads the horizontal direction electronically"],["Vertical circle (encoder)","Reads the vertical (zenith) angle electronically"],["EDM","Measures slope distance to a prism or surface by phase/pulse timing"],["Tribrach + foot screws","Detachable base; foot screws level the instrument"],["Optical/laser plummet","Centers the vertical axis over the ground mark"],["Circular & plate (tubular) levels","Coarse and fine leveling references"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0001-0000-0000-000000000002', '15139528-33df-4856-94bb-dff559fa6688', 'text', '{"html":"<h3>Centering and Leveling</h3><p>A correct setup satisfies two independent conditions at once: the instrument''s <strong>vertical axis must pass through the ground mark</strong> (centering) and that <strong>vertical axis must be truly plumb</strong> (leveling). A practical sequence is: spread the tripod at a comfortable height with the head roughly level and roughly over the point; press the legs in; use the <strong>optical/laser plummet</strong> to bring the instrument over the mark by adjusting two legs; use the <strong>foot screws</strong> to center the circular bubble; then loosen the tribrach clamp and slide the instrument to recenter the plummet exactly; finally use the <strong>plate (tubular) level</strong> and foot screws to level precisely, checking the bubble stays centered as you rotate the instrument 90&deg; and 180&deg;.</p><p>The two operations interact: centering with the plummet is only valid <em>after</em> the instrument is level, because tilting the vertical axis moves the plummet line off the mark. Iterate &mdash; level, recenter, re-level &mdash; until both hold simultaneously. A setup that is centered but not level, or level but not centered, injects systematic position error into every shot taken from it.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0001-0000-0000-000000000003', '15139528-33df-4856-94bb-dff559fa6688', 'callout', '{"type":"warning","text":"Centering error is unforgiving on short sights: an instrument or target 5 mm off the mark produces a far larger angular error on a 10 m shot than on a 200 m shot. On short setups (building corners, control ties), force-centering with tribrach adapters and careful plummet checks matters most."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0001-0000-0000-000000000004', '15139528-33df-4856-94bb-dff559fa6688', 'text', '{"html":"<h3>Height of Instrument and Height of Reflector</h3><p>To get <strong>elevations</strong> from a total station you must record two vertical offsets. The <strong>height of instrument (HI)</strong> is the vertical distance from the occupied point (the mark on the ground) up to the instrument''s <strong>trunnion (horizontal) axis</strong> &mdash; the tilting axis of the telescope, not the top of the tribrach. The <strong>height of reflector (HR)</strong>, also called target height or rod height, is the vertical distance from the observed point up to the <strong>center of the prism</strong>. Both are typed into the data collector before observing.</p><p>The instrument measures the slope distance and the zenith angle to the prism; from these it computes the vertical component between the trunnion axis and the prism center. The point''s elevation is then the occupied elevation plus HI plus that vertical component minus HR. A single wrong HI or HR offsets <em>every</em> elevation from that setup by the same amount &mdash; a classic blunder. Always measure HI to the marked index on the side of the instrument, confirm the prism pole height, and note both in the field record.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0001-0000-0000-000000000005', '15139528-33df-4856-94bb-dff559fa6688', 'equation', '{"latex":"Elev_B = Elev_A + HI + S\\cos(Z) - HR","label":"Trigonometric elevation from a total station setup (Z = zenith angle, S = slope distance)","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0001-0000-0000-000000000006', '15139528-33df-4856-94bb-dff559fa6688', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Vertical geometry of a setup — HI to the trunnion axis, HR to the prism center, and the measured slope distance and zenith angle between them."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0001-0000-0000-000000000007', '15139528-33df-4856-94bb-dff559fa6688', 'key_takeaways', '{"title":"Key Takeaways","items":["A total station = electronic theodolite (angles) + EDM (distances) + processor/data collector in one unit.","Setup requires simultaneous centering (axis over the mark) and leveling (axis plumb); the two interact and must be iterated.","Measure HI to the trunnion axis and HR to the prism center; a wrong HI/HR offsets every elevation equally.","Centering error hurts most on short sights, so use force-centering and careful plummet checks on close shots."]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0002-0000-0000-000000000000', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'text', '{"html":"<h3>Electronic Angle Measurement</h3><p>A total station replaces the optical micrometer of a classical theodolite with an <strong>electronic angle encoder</strong> on each circle. Two common designs exist. <strong>Absolute encoders</strong> carry a coded pattern (often a binary or pseudo-random track) so that each position on the circle has a unique, directly readable code; the instrument knows its orientation the moment it powers up. <strong>Incremental encoders</strong> count fine, evenly spaced graduations as the circle turns, referenced to an index, and accumulate the count to a reading. In both, a light source and photodetector array sense the graduations, and the processor interpolates between lines to reach a resolution of a few arc-seconds.</p><p>Electronic reading removes the human micrometer-estimation error and the transposition blunders of hand-recorded directions, but it does <em>not</em> remove instrument-axis errors. <strong>Collimation</strong> (line of sight not perpendicular to the trunnion axis) and <strong>vertical-circle index</strong> error remain; they are removed by observing in both <strong>face left and face right</strong> (direct and reverse) and meaning the two, exactly as with an optical theodolite. Many total stations measure and store a dual-axis tilt-sensor correction to compensate small residual mislevelment of the vertical axis.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0002-0000-0000-000000000001', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'text', '{"html":"<h3>How an EDM Measures Distance</h3><p>The <strong>electronic distance meter (EDM)</strong> sends modulated infrared or laser light to a <strong>retroreflective prism</strong> (or, in reflectorless mode, to a surface) and analyzes the returned signal. Two measuring principles dominate. In the <strong>phase-comparison method</strong>, the carrier is amplitude-modulated at several known wavelengths; the instrument measures the <em>phase shift</em> between outgoing and returning signals for each wavelength and resolves the integer number of whole wavelengths (the &lsquo;ambiguity&rsquo;) from the coarser modulations. In the <strong>pulse (time-of-flight) method</strong>, the instrument emits short light pulses and measures the elapsed travel time directly; distance is half the round-trip time multiplied by the speed of light in air.</p><p>Both methods depend on the <strong>velocity of light through the atmosphere</strong>, which varies with temperature, pressure, and humidity. The instrument applies a <strong>ppm (parts-per-million) atmospheric correction</strong> based on entered or sensed met data, plus a <strong>prism constant</strong> (the offset between the prism''s optical center and the point it represents). Without the correct prism constant and ppm, distances carry a systematic scale/offset error. The result of the EDM is always a <strong>slope distance</strong> along the line of sight, which must still be reduced to horizontal and vertical components.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0002-0000-0000-000000000002', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'equation', '{"latex":"H = S\\,\\sin(Z), \\qquad V = S\\,\\cos(Z)","label":"Reduction of slope distance S to horizontal (H) and vertical (V) using the zenith angle Z","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0002-0000-0000-000000000003', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'text', '{"html":"<h3>From Slope to Horizontal and Vertical</h3><p>Surveying coordinates are computed in a horizontal plane, so the measured <strong>slope distance S</strong> must be split into a <strong>horizontal distance H</strong> and a <strong>vertical distance V</strong>. Using the <strong>zenith angle Z</strong> (measured from the vertical, so a level sight is Z = 90&deg;), the geometry is simply H = S·sin(Z) and V = S·cos(Z). Some instruments report the <strong>vertical angle</strong> (from the horizontal) instead; then H = S·cos(v) and V = S·sin(v). The processor does this automatically, but the surveyor must know which convention is in use to check field values by hand.</p><p>For long, precise lines the instrument also applies <strong>earth-curvature and refraction</strong> corrections to the vertical component, because a level line of sight is not a true horizontal over distance and light bends in the atmosphere. The combined correction is commonly taken as about <strong>0.0675 K²</strong> feet (K in thousands of feet) and improves trigonometric elevations on lines beyond a few hundred feet. For ordinary topo at short range the effect is negligible, but for control and long stakeout it is not.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0002-0000-0000-000000000004', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'callout', '{"type":"info","text":"Always confirm the prism constant in the data collector matches the prism actually on the pole (common values are 0 mm and −30 mm). Mixing a −30 mm prism with a 0 mm setting biases every distance by 30 mm — a silent, repeatable error that closure checks may not flag."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0002-0000-0000-000000000005', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A slope distance S at zenith angle Z resolves into horizontal H = S·sin(Z) and vertical V = S·cos(Z)."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0002-0000-0000-000000000006', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'key_takeaways', '{"title":"Key Takeaways","items":["Electronic encoders (absolute or incremental) read angles directly, removing reading blunders but not collimation/index errors — still observe face left and face right.","EDMs measure slope distance by phase comparison or pulse time-of-flight; both need the correct prism constant and atmospheric (ppm) correction.","Reduce slope to horizontal with H = S·sin(Z) and to vertical with V = S·cos(Z) using the zenith angle.","Apply curvature-and-refraction correction to vertical components on long lines."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0003-0000-0000-000000000000', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'text', '{"html":"<h3>The Data Collector''s Role</h3><p>A <strong>data collector</strong> is a rugged handheld (or the instrument''s own onboard keypad) running <strong>field software</strong> that orchestrates the survey. It commands the total station to read angles and distances, prompts the surveyor for setup information, computes coordinates in real time, applies feature codes, and stores everything to a <strong>job file</strong>. It is the modern replacement for the paper field book: faster, less error-prone for arithmetic, and directly importable to office software. Common field packages include Trimble Access, Carlson SurvCE/SurvPC, Leica Captivate, and TopCon MAGNET Field, but the workflow concepts are the same across brands.</p><p>The collector manages a <strong>point database</strong> of known control, observed sideshots, and computed stakeout points, each with a number/name, coordinates, and a <strong>feature code</strong>. It also keeps the <strong>raw measurement record</strong>. Good field software lets the surveyor review a setup''s residuals on the spot, re-shoot a bad backsight, and flag suspect points before leaving the site &mdash; catching errors while they are still cheap to fix.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0003-0000-0000-000000000001', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'text', '{"html":"<h3>Setting Up a Job: Occupy, Backsight, Orient</h3><p>Before any feature is located, the setup must be <strong>oriented</strong> into the job''s coordinate system. The standard sequence is: select or enter the <strong>occupied point</strong> (the known coordinate the instrument stands over) and its HI; select the <strong>backsight</strong> &mdash; either a second known point or a known azimuth/bearing &mdash; and its HR; sight the backsight precisely and accept it. The software then computes the <strong>orientation</strong> (the rotation that aligns the instrument''s horizontal circle with grid north) so that every subsequent shot yields a correct coordinate. Many crews take a <strong>backsight check</strong> to a second known point to confirm the setup before collecting data.</p><p>From an oriented setup, each observed point (a <strong>sideshot</strong> or <strong>radial</strong> shot) is located by one angle-and-distance reading. The surveyor assigns a <strong>feature code</strong> (e.g., EP for edge of pavement, TREE, IP for iron pin) and optionally <strong>line/connect codes</strong> so the office software can draw linework automatically. Disciplined, consistent coding in the field is what turns a cloud of points into a usable drawing without hours of office cleanup.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0003-0000-0000-000000000002', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'table', '{"headers":["Setup element","What it provides"],"rows":[["Occupied point + HI","Where the instrument stands and its vertical offset"],["Backsight point/azimuth + HR","Reference direction to orient the horizontal circle"],["Orientation","Rotation aligning the circle with the job''s north"],["Backsight check","Independent confirmation the setup is correct"],["Feature/line codes","Attribute and connectivity for automated linework"]]}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0003-0000-0000-000000000003', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'text', '{"html":"<h3>Raw Data vs. Reduced Coordinates</h3><p>Field software stores two related but distinct things. <strong>Reduced coordinates</strong> are the final northings, eastings, and elevations the instrument computed for each point. <strong>Raw data</strong> are the underlying observations &mdash; occupied and backsight points, HI and HR, horizontal and zenith angles, slope distances, and prism/atmospheric settings &mdash; usually in a vendor format or the open <strong>.rw5</strong> raw file. Coordinates are convenient, but raw data are the <strong>legal and technical record</strong>: they let the office <em>re-reduce</em> the survey if a control coordinate, HI, or prism constant was wrong, and they document exactly how each point was measured.</p><p>This separation matters for quality and defensibility. If a backsight is later found to be on the wrong point, a coordinate-only file is ruined, but a raw file can be reprocessed with the corrected backsight and every dependent point recomputed. For this reason, professional practice and survey standards expect the raw observations to be preserved, not just the tidy coordinate list.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0003-0000-0000-000000000004', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'callout', '{"type":"warning","text":"Texas differs / practice note: Texas surveying standards (22 TAC Chapter 138, Subchapter E) require that the basis of bearing, monumentation, and the relationship between record monuments and surveyed boundaries be documented. Retaining the raw observation file (with HI/HR, backsight, and basis of bearing) is the practical way to support those records and to re-reduce work if control is later corrected."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0003-0000-0000-000000000005', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'key_takeaways', '{"title":"Key Takeaways","items":["The data collector + field software controls the instrument, stores points and raw data, and computes coordinates in the field.","Orient every setup by occupying a known point and backsighting a known point/azimuth; verify with a backsight check.","Code features consistently in the field so office software can build linework automatically.","Always preserve the raw observation file, not just coordinates, so the survey can be audited and re-reduced."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0004-0000-0000-000000000000', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'text', '{"html":"<h3>Stakeout Is Topo in Reverse</h3><p><strong>Stakeout</strong> (also called <strong>layout</strong> or <strong>setting out</strong>) is the inverse of topographic data collection. In topo you observe an existing feature and the software records its coordinate. In stakeout you start with a <strong>design coordinate</strong> &mdash; a building corner, a curb return, a pipe invert, a property corner to set &mdash; and the instrument guides you to put a stake exactly there on the ground. Construction layout, boundary monument setting, and grade staking are all stakeout. The math is a <strong>coordinate inverse</strong>: given the occupied point and the design point, compute the azimuth and horizontal distance between them.</p><p>The crew first loads or enters the <strong>design point list</strong> (often from the engineer''s coordinate file) into the data collector, sets up and <strong>orients</strong> over known control exactly as for topo, and runs a backsight check. Then for each design point the software directs the instrument operator and rodperson toward the target, reads the rod''s current position, and reports how far and which way to move until the rod is within tolerance of the design coordinate.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0004-0000-0000-000000000001', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'text', '{"html":"<h3>Reading the Guidance</h3><p>Modern field software gives intuitive directions. <strong>In/out</strong> (sometimes &lsquo;go/come&rsquo; or &lsquo;toward/away&rsquo;) moves the rod along the line of sight from the instrument; <strong>left/right</strong> moves it perpendicular to that line, from the operator''s or the rodperson''s stated perspective. The collector updates these offsets each time a shot is taken to the prism, converging on the design point. When horizontal position is within tolerance, the software reports the vertical difference as <strong>cut</strong> (the ground is above design, dig down) or <strong>fill</strong> (the ground is below design, build up), computed from the staked elevation against the design elevation.</p><p>Robotic total stations let one person stake alone: the instrument tracks and locks onto the prism while the rodperson reads the guidance on a controller at the rod. Whether conventional or robotic, the rodperson should <strong>plumb the rod</strong> carefully and <strong>re-observe</strong> after driving the stake, because the act of setting the hub can nudge the position. Always record the as-staked coordinate so the set point is documented, not just intended.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0004-0000-0000-000000000002', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'equation', '{"latex":"Az = \\operatorname{atan2}(E_2 - E_1,\\; N_2 - N_1), \\qquad D = \\sqrt{(N_2-N_1)^2 + (E_2-E_1)^2}","label":"Inverse: azimuth and horizontal distance from setup (N1,E1) to design point (N2,E2)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0004-0000-0000-000000000003', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'callout', '{"type":"warning","text":"Garbage in, garbage out: stakeout faithfully reproduces whatever the orientation and design file say. A wrong backsight, a transposed northing/easting, or a design point on the wrong datum will be staked precisely — in the wrong place. Always run an independent check (a known point or a second control backsight) before setting production stakes."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0004-0000-0000-000000000004', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'table', '{"headers":["Guidance term","Meaning"],"rows":[["In / Out (Go / Come)","Move the rod toward or away from the instrument along the sight line"],["Left / Right","Move the rod perpendicular to the sight line"],["Cut","Ground is above design elevation — excavate down by that amount"],["Fill","Ground is below design elevation — build up by that amount"],["Δ (within tolerance)","Horizontal offset is small enough to set the stake"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0004-0000-0000-000000000005', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Stakeout guidance — the software resolves the rod-to-design vector into in/out (along sight) and left/right (perpendicular) corrections."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0004-0000-0000-000000000006', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'key_takeaways', '{"title":"Key Takeaways","items":["Stakeout starts from design coordinates and guides a stake to that ground position — the reverse of topo.","The collector inverses from the setup to each design point and reports in/out, left/right, then cut/fill.","A verified orientation and design list are mandatory; an error there is staked perfectly in the wrong place.","Re-observe and record the as-staked coordinate after driving the hub."]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0005-0000-0000-000000000000', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', 'text', '{"html":"<h3>Measuring Without a Prism</h3><p><strong>Reflectorless</strong> measurement (also <strong>direct reflex</strong>, DR) lets a total station measure distance to a <strong>natural surface</strong> &mdash; brick, concrete, rock, asphalt &mdash; without a retroreflective prism. The EDM emits a narrow, often visible laser; the surface <strong>scatters</strong> a small fraction of that light back, and the receiver times or phase-compares it just as it would a prism return. Because diffuse surfaces return far less signal than a prism, reflectorless mode has a <strong>shorter range</strong> and <strong>lower precision</strong>, but it unlocks points a rodperson could never safely reach.</p><p>Typical reflectorless range runs from tens of meters to several hundred meters depending on the instrument, the surface reflectivity, and the angle of incidence. A light-colored, flat surface faced squarely returns the strongest signal; a dark, wet, glassy, or steeply angled surface returns much less and may yield a noisy or failed measurement. The <strong>prism constant must be set to the reflectorless (DR) value</strong>, not a prism offset, or the distance will be biased.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0005-0000-0000-000000000001', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', 'text', '{"html":"<h3>Where Reflectorless Shines — and Where It Doesn''t</h3><p>Reflectorless is invaluable for points that are <strong>inaccessible or unsafe</strong>: building corners high on a facade, bridge members, the face of a retaining wall, rock faces, the centerline of a busy roadway, or features inside a fenced enclosure. It speeds topographic and as-built work by letting one operator locate features without sending a rodperson into hazardous or restricted ground. For deformation monitoring of structures it can sample many points on a face quickly.</p><p>Its weaknesses follow from the physics. The laser beam has a finite <strong>footprint (beam divergence)</strong> that grows with distance; at long range the measured distance is an average over that spot, not a pinpoint. Aiming at an <strong>edge</strong> (a wall corner against the sky, a curb lip) can split the beam between near and far surfaces, returning a blended or wrong distance. Oblique incidence lengthens the effective path and weakens the return. Critical reflectorless points should be <strong>checked</strong> &mdash; shot twice, or compared with a prism shot to an adjacent reachable point.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0005-0000-0000-000000000002', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', 'callout', '{"type":"warning","text":"Laser safety: the visible/invisible EDM beam in reflectorless mode is more powerful than a typical pointer. Never aim it at a person''s eyes or at mirrored/reflective surfaces (glass, polished metal, vehicle mirrors), and follow the instrument''s laser-class precautions. Reflective surfaces can also return spurious distances."}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0005-0000-0000-000000000003', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', 'table', '{"headers":["Factor","Effect on reflectorless accuracy"],"rows":[["Surface reflectivity","Light/flat surfaces return strong signal; dark/wet/glassy surfaces weaken or fail it"],["Angle of incidence","Oblique surfaces weaken the return and bias the path"],["Beam divergence (range)","Spot grows with distance; reading averages over the footprint"],["Edges / mixed targets","Beam straddles near/far surfaces — blended, unreliable distance"],["Prism/DR constant","Must be set to the DR value, not a prism offset"]]}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0005-0000-0000-000000000004', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Beam divergence enlarges the laser footprint with range; aiming near an edge can split the beam between near and far surfaces."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0005-0000-0000-000000000005', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', 'key_takeaways', '{"title":"Key Takeaways","items":["Reflectorless (DR) EDM measures to a surface via scattered light — no prism, but shorter range and lower precision.","It is ideal for inaccessible/unsafe points; set the prism constant to the DR value, not a prism offset.","Beam divergence, edges, oblique angles, and dark/wet/glassy surfaces degrade accuracy — aim at the true point and verify critical shots.","Observe laser-safety precautions; never aim at eyes or reflective surfaces."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0006-0000-0000-000000000000', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'text', '{"html":"<h3>Getting Data Out of the Field</h3><p>Once observations are collected, the job must move from the <strong>data collector to the office software</strong> for adjustment, COGO, and drafting. Transfer happens by USB cable, removable card, Wi-Fi/Bluetooth, or cloud sync, depending on the system. The office software &mdash; Carlson, Civil 3D, TBC (Trimble Business Center), MicroSurvey, etc. &mdash; imports the field files, recomputes or adjusts as needed, and turns coded points into linework and a finished survey drawing. The goal is a clean, lossless handoff: nothing renamed, nothing dropped, and the raw observations preserved.</p><p>Two distinct file families travel together. A <strong>coordinate file</strong> is a simple list of points and their reduced coordinates, often comma-delimited in a fixed order such as <strong>PNEZD</strong> (Point, Northing, Easting, Z/elevation, Description). A <strong>raw data file</strong> contains the underlying observations &mdash; setups, backsights, HI/HR, angles, distances &mdash; in a vendor or open format. The coordinate file is what most quickly populates a drawing; the raw file is what protects you when something needs to be reprocessed.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0006-0000-0000-000000000001', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'table', '{"headers":["File type","Typical format / example","Used for"],"rows":[["Coordinate file","ASCII PNEZD (.csv/.txt): point, N, E, Z, desc","Importing points and linework into CAD/COGO"],["Raw data file",".rw5, .raw, vendor JOB/DC","Re-reducing/adjusting; legal/technical record"],["Exchange format","LandXML (.xml)","Sharing points, surfaces, alignments between packages"],["Drawing","DWG/DXF","Final survey/CAD deliverable"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0006-0000-0000-000000000002', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'text', '{"html":"<h3>The Office Workflow</h3><p>A typical sequence in the office is: <strong>(1) download</strong> the job (raw + coordinate files) and back it up immediately; <strong>(2) import</strong> the raw file into the office software and <strong>re-reduce</strong> it &mdash; confirming control coordinates, HI/HR, prism constants, and basis of bearing &mdash; correcting any field setup error and recomputing every dependent point; <strong>(3) adjust</strong> any traverse or network for closure; <strong>(4) import or generate the coordinate/point file</strong> with feature codes; and <strong>(5) draft</strong> the survey, building linework from the codes and adding annotation. Re-reducing from raw, rather than trusting the field coordinates blindly, is what lets you fix a mis-keyed backsight or HI after the fact.</p><p>Throughout, <strong>data management</strong> discipline matters: keep a consistent point-numbering scheme so two jobs do not collide, maintain a shared <strong>feature-code library</strong> so EP/TREE/IP mean the same thing every time, and <strong>archive the raw files</strong> with the project. The transfer is also where units and datum mismatches surface &mdash; confirm U.S. survey foot vs. international foot, and the correct State Plane zone/datum, before merging into existing control.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0006-0000-0000-000000000003', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'callout', '{"type":"warning","text":"Texas note: State Plane work in Texas uses NAD83 in one of several Texas zones, and the U.S. survey foot has historically been the convention. Mixing the international foot with U.S.-survey-foot State Plane coordinates introduces a scale error that grows with distance from the origin — confirm the foot definition and zone on import."}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0006-0000-0000-000000000004', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'callout', '{"type":"info","text":"PNEZD order matters: many imports fail or silently swap Northing and Easting if the column order in the file does not match what the software expects. Always confirm the field order (PNEZD vs. PENZD) when importing an ASCII coordinate file."}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0006-0000-0000-000000000005', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'key_takeaways', '{"title":"Key Takeaways","items":["Coordinate files (e.g., PNEZD ASCII) carry reduced points; raw files (e.g., .rw5) carry the observations.","Office workflow: download/back up → import and re-reduce raw → adjust → generate coordinates/codes → draft.","Re-reducing from raw lets you correct a field setup error and recompute dependent points.","Manage point numbering and feature codes consistently, archive raw data, and verify foot definition and State Plane zone/datum on import."]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0007-0000-0000-000000000000', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'text', '{"html":"<h3>Instrument Errors and Calibration</h3><p>Even a well-built total station carries small mechanical and electronic <strong>axis errors</strong> that calibration measures and the firmware (or field procedure) compensates. The chief ones are <strong>line-of-sight (collimation) error</strong> &mdash; the sight line not perpendicular to the trunnion axis; <strong>trunnion (horizontal) axis tilt</strong> &mdash; that axis not perpendicular to the vertical axis; <strong>vertical-circle index error</strong> &mdash; the zenith reading not exactly 90&deg; on a level sight; and EDM <strong>additive (zero) constant</strong> and <strong>scale</strong> errors. Manufacturers provide an onboard calibration routine that has the operator sight a target in both faces; the instrument computes and stores correction values it then applies to every reading.</p><p>Many of these errors are also <strong>self-cancelling in good field practice</strong>: observing each angle in <strong>face left and face right</strong> and meaning the two removes collimation, trunnion-tilt, and vertical-index error to first order. Calibration is what keeps single-face shots honest and flags an instrument that has drifted out of tolerance. EDM additive constant should be checked against a baseline of known distances periodically, especially after a knock or a repair.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0007-0000-0000-000000000001', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'table', '{"headers":["Error","What it is","How it''s handled"],"rows":[["Collimation (line of sight)","Sight line not ⊥ to trunnion axis","Face-left/face-right mean; stored correction"],["Trunnion-axis tilt","Horizontal axis not ⊥ to vertical axis","Two-face observation; calibration"],["Vertical-index error","Zenith ≠ 90° on a level sight","Two-face mean; index calibration"],["EDM additive (zero) constant","Fixed distance offset","Baseline check; enter/adjust constant"],["Compensator/tilt","Residual vertical-axis mislevelment","Dual-axis compensator correction"]]}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0007-0000-0000-000000000002', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'text', '{"html":"<h3>Resection and Free-Stationing</h3><p>A great advantage of the total station is that you need not occupy a known monument at all. In <strong>resection</strong> (also <strong>free-stationing</strong>), the instrument is set up at a convenient unknown point and sights <strong>two or more known control points</strong>; from the observed angles and distances the software solves the <strong>instrument''s own coordinates and orientation</strong>. This frees the surveyor to set up wherever the visibility and geometry are best &mdash; in the middle of a site, off the actual control &mdash; and is the backbone of construction layout from a temporary &lsquo;free station&rsquo;.</p><p>Resection geometry matters: sighting points that are nearly in line with the instrument, or clustered in a narrow angle, gives a weak, ill-conditioned solution. Strong resections use well-distributed control with good intersection angles, and using <strong>three or more</strong> known points provides redundancy and a residual check on the fit. Distances (not just angles) to the known points greatly strengthen the solution, which is why a total-station resection is far more robust than the classical angle-only three-point problem.</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0007-0000-0000-000000000003', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'equation', '{"latex":"N_P = N_1 + D\\cos(Az), \\qquad E_P = E_1 + D\\sin(Az)","label":"Radial coordinate of a point P from an oriented setup at (N1,E1): azimuth Az, horizontal distance D","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0007-0000-0000-000000000004', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'text', '{"html":"<h3>Radial Topo and Routine Care</h3><p><strong>Radial topography</strong> (radial topo) is the everyday total-station method: from a single oriented setup, each feature is located by <strong>one horizontal direction and one slope distance</strong>, and the processor radiates a coordinate from the station to the point using N_P = N_1 + D·cos(Az) and E_P = E_1 + D·sin(Az). Hundreds of points can be picked up quickly this way; combined with resection, a crew can set up wherever convenient, orient, and radiate topo without ever standing on a monument.</p><p>None of this is trustworthy if the instrument is mistreated. <strong>Care practices:</strong> transport in its padded case; never leave it unattended on the tripod; carry it upright and lock the clamps lightly; keep the lens and reflectors clean with proper optics cloth; protect the EDM optics from rain and dust; let the instrument <strong>equalize to ambient temperature</strong> before precise work; and avoid sighting through heat shimmer. <strong>Field checks:</strong> a daily two-face check on a distant target, a periodic EDM baseline check, and a backsight check every setup catch problems before they corrupt a job. Send the instrument for professional calibration on the manufacturer''s schedule or after any hard knock.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0007-0000-0000-000000000005', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'callout', '{"type":"warning","text":"Texas / standards note: Texas surveying standards (22 TAC §138.83, Precision and Accuracy) set positional/closure tolerances for the survey category being performed. Keeping the instrument calibrated, performing two-face and backsight checks, and documenting them is how a surveyor demonstrates the measurements meet the required accuracy."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0007-0000-0000-000000000006', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A resected (free-station) setup solves its own coordinates from known points, then radiates topo shots to features by single angle-and-distance observations."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee1010-0007-0000-0000-000000000007', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'key_takeaways', '{"title":"Key Takeaways","items":["Collimation, trunnion-tilt, and vertical-index errors are removed by two-face observation and stored calibration corrections; check the EDM additive constant on a baseline.","Resection/free-stationing solves the instrument''s coordinates from two or more known points — set up anywhere; use 3+ well-distributed points for a strong solution.","Radial topo radiates a coordinate to each feature from one oriented setup using N = N₁ + D·cos(Az), E = E₁ + D·sin(Az).","Routine care, daily two-face and backsight checks, temperature equalization, and scheduled calibration keep results within standard tolerances."]}'::jsonb, 7);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000001', 'Total station', 'An instrument integrating an electronic theodolite, an EDM, and an onboard processor/data collector, so that angle and distance to a point are captured from a single setup and combined into coordinates.', NULL, 'c100000a-0000-0000-0000-00000000000a', '15139528-33df-4856-94bb-dff559fa6688', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000002', 'Height of instrument (HI)', 'The vertical distance from the occupied ground mark up to the instrument''s trunnion (horizontal) axis. Required, together with HR, to compute trigonometric elevations.', 'Measured to the tilting axis of the telescope, not the top of the tribrach.', 'c100000a-0000-0000-0000-00000000000a', '15139528-33df-4856-94bb-dff559fa6688', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000003', 'Centering vs. leveling', 'Centering places the instrument''s vertical axis directly over the ground mark; leveling makes that vertical axis truly plumb. Both must be true at once, so the surveyor iterates between the plummet and the foot screws.', NULL, 'c100000a-0000-0000-0000-00000000000a', '15139528-33df-4856-94bb-dff559fa6688', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000004', 'Electronic distance meter (EDM)', 'The distance-measuring component of a total station. It sends modulated light to a prism or surface and measures distance by phase comparison of the returned signal or by timing a pulse''s round trip, then applies prism-constant and atmospheric corrections.', NULL, 'c100000a-0000-0000-0000-00000000000a', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000005', 'Zenith angle', 'A vertical angle measured downward from the local vertical (zenith), so a perfectly level line of sight reads 90°. Horizontal distance = S·sin(Z); vertical distance = S·cos(Z).', NULL, 'c100000a-0000-0000-0000-00000000000a', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000006', 'Prism constant', 'The fixed offset between a retroreflective prism''s optical center and the physical point it represents (commonly 0 mm or −30 mm). It must be entered correctly or every EDM distance carries that systematic error.', 'A mismatch produces a constant, repeatable bias in distance.', 'c100000a-0000-0000-0000-00000000000a', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000007', 'Data collector', 'A rugged handheld (or onboard keypad) running field software that controls the total station, stores points, raw observations, and feature codes, and computes coordinates in real time — the digital replacement for the paper field book.', NULL, 'c100000a-0000-0000-0000-00000000000a', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000008', 'Backsight', 'A second known point (or a known azimuth) sighted from the occupied station to orient the instrument''s horizontal circle to the job''s coordinate system before any sideshots are taken.', NULL, 'c100000a-0000-0000-0000-00000000000a', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000009', 'Raw data (.rw5)', 'The recorded underlying observations — occupied/backsight points, HI/HR, angles, slope distances, and instrument settings — as opposed to reduced coordinates. Raw data allow a survey to be re-reduced and audited if a control value was wrong.', 'Keep this, not just the coordinate list.', 'c100000a-0000-0000-0000-00000000000a', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000010', 'Stakeout (layout)', 'The process of placing stakes/monuments at predetermined design coordinates on the ground. It is the inverse of topo: the instrument guides a rod to where a point should be, rather than recording where an existing point is.', NULL, 'c100000a-0000-0000-0000-00000000000a', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000011', 'Coordinate inverse', 'The computation of the azimuth and horizontal distance between two known coordinates, Az = atan2(ΔE, ΔN) and D = √(ΔN² + ΔE²). Stakeout software inverses from the setup to each design point to direct the rod.', NULL, 'c100000a-0000-0000-0000-00000000000a', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000012', 'Cut and fill', 'In grade staking, cut means the existing ground is above the design elevation (excavate down) and fill means it is below (build up). The data collector reports the value once the horizontal position is within tolerance.', 'Cut = dig down; fill = build up.', 'c100000a-0000-0000-0000-00000000000a', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000013', 'Reflectorless (direct-reflex) measurement', 'EDM measurement to a natural surface without a prism, using the light scattered back from the material. It reaches inaccessible points but has shorter range and lower precision than prism measurement.', NULL, 'c100000a-0000-0000-0000-00000000000a', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000014', 'Beam divergence', 'The widening of the EDM laser footprint with distance. At range the reflectorless reading averages over the spot, so it cannot resolve a feature finer than the footprint and can straddle edges.', 'Why aiming near a wall corner can give a blended distance.', 'c100000a-0000-0000-0000-00000000000a', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000015', 'Coordinate file (PNEZD)', 'An ASCII point list, commonly comma-delimited in Point–Northing–Easting–Z(elevation)–Description order, used to import reduced points and linework into CAD/COGO software.', NULL, 'c100000a-0000-0000-0000-00000000000a', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000016', 'LandXML', 'An open XML exchange format for transferring survey data — points, surfaces, alignments, parcels — between different software packages without proprietary lock-in.', 'Vendor-neutral interchange of points/surfaces/alignments.', 'c100000a-0000-0000-0000-00000000000a', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000017', 'Re-reduction', 'Recomputing a survey in the office from its raw observations — verifying control, HI/HR, prism constants, and basis of bearing — so that a field setup error can be corrected and all dependent points recomputed.', NULL, 'c100000a-0000-0000-0000-00000000000a', 'd8e1362b-c24e-438e-842c-73064b2b656e', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000018', 'Collimation error', 'An instrument error in which the line of sight is not perpendicular to the trunnion (horizontal) axis. It is removed by meaning face-left and face-right observations and by stored calibration corrections.', NULL, 'c100000a-0000-0000-0000-00000000000a', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000019', 'Resection (free-stationing)', 'A method that places the instrument at an unknown point and solves its own coordinates and orientation by observing two or more known control points. It lets the surveyor set up wherever visibility and geometry are best, without occupying a monument.', 'Use three or more well-distributed points for a strong, checked solution.', 'c100000a-0000-0000-0000-00000000000a', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000020', 'Radial topography', 'Locating features by single horizontal-direction and slope-distance observations from one oriented setup; the processor radiates a coordinate to each point as N = N₁ + D·cos(Az), E = E₁ + D·sin(Az).', NULL, 'c100000a-0000-0000-0000-00000000000a', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee1040-0000-0000-0000-000000000021', 'Two-face observation', 'Observing a target in both face left (direct) and face right (reverse) and meaning the readings, which cancels collimation, trunnion-axis tilt, and vertical-index errors to first order.', 'Direct and reverse, then average.', 'c100000a-0000-0000-0000-00000000000a', '549ace82-2dbd-4aef-84f1-6d48afc86d79', 'surveying', ARRAY['buildout','module-10']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000001', 'Which three measuring functions does a total station integrate into one instrument?', 'multiple_choice', '["GPS positioning, leveling, and photogrammetry","Electronic angle measurement, electronic distance measurement, and onboard processing/storage","Magnetic compass, chaining, and plane-table plotting","Barometric altimetry, tape distance, and manual angle reading"]'::jsonb, 'Electronic angle measurement, electronic distance measurement, and onboard processing/storage', 'A total station combines an electronic theodolite (angles), an EDM (distances), and a microprocessor/data collector. The other options describe unrelated or obsolete techniques.', 'easy', 'c100000a-0000-0000-0000-00000000000a', '15139528-33df-4856-94bb-dff559fa6688', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000002', 'The height of instrument (HI) entered in the data collector should be measured to which part of the instrument?', 'multiple_choice', '["The top of the tripod head","The center of the prism","The trunnion (horizontal) axis","The bottom of the tribrach"]'::jsonb, 'The trunnion (horizontal) axis', 'HI is the vertical distance from the occupied mark to the trunnion axis (the telescope''s tilting axis), because that is where the vertical angle is measured from. HR is measured to the prism center.', 'medium', 'c100000a-0000-0000-0000-00000000000a', '15139528-33df-4856-94bb-dff559fa6688', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000003', 'Why must centering and leveling be iterated rather than done once each?', 'multiple_choice', '["The EDM cannot read until both are perfect","Tilting the vertical axis during leveling moves the plummet line off the mark, so re-centering is needed","The data collector overwrites the coordinate each time","Foot screws change the prism constant"]'::jsonb, 'Tilting the vertical axis during leveling moves the plummet line off the mark, so re-centering is needed', 'Centering is only valid when the instrument is level, and leveling can shift the plummet off the point. The two conditions interact, so the surveyor alternates between them until both hold simultaneously.', 'medium', 'c100000a-0000-0000-0000-00000000000a', '15139528-33df-4856-94bb-dff559fa6688', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000004', 'Observing a horizontal angle in both face left and face right and meaning the two readings primarily removes which errors?', 'multiple_choice', '["Atmospheric refraction and earth curvature","Collimation, trunnion-axis tilt, and vertical-index errors","Prism constant and ppm scale errors","Centering and HI measurement blunders"]'::jsonb, 'Collimation, trunnion-axis tilt, and vertical-index errors', 'Two-face observation cancels instrument-axis errors (collimation, trunnion tilt, vertical index) to first order. Atmospheric, prism-constant, and centering errors are addressed by other means.', 'medium', 'c100000a-0000-0000-0000-00000000000a', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000005', 'A slope distance of 250.00 ft is measured at a zenith angle of 86°00''. What is the horizontal distance (to 0.01 ft)?', 'numeric_input', '[]'::jsonb, '249.39', 'H = S·sin(Z) = 250.00 × sin(86°) = 250.00 × 0.99756 = 249.39 ft.', 'medium', 'c100000a-0000-0000-0000-00000000000a', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000006', 'Setting a 0 mm prism constant while actually using a −30 mm prism will cause:', 'multiple_choice', '["A random scatter in the measured angles","A constant, repeatable 30 mm bias in every measured distance","An error only on reflectorless shots","No effect, because the software auto-detects the prism"]'::jsonb, 'A constant, repeatable 30 mm bias in every measured distance', 'The prism constant is a fixed offset between the prism''s optical center and the point. A mismatch biases every distance by that amount — a systematic, repeatable error that closure checks may not reveal.', 'medium', 'c100000a-0000-0000-0000-00000000000a', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000007', 'An EDM that times how long a light pulse takes to travel to the target and back is using which measuring principle?', 'multiple_choice', '["Phase comparison","Pulse time-of-flight","Triangulation","Barometric ranging"]'::jsonb, 'Pulse time-of-flight', 'The pulse (time-of-flight) method measures the round-trip travel time of a light pulse; distance is half that time times the speed of light in air. Phase comparison instead measures the phase shift of a continuously modulated signal.', 'easy', 'c100000a-0000-0000-0000-00000000000a', 'ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000008', 'Before collecting any sideshots, an oriented total-station setup requires which two known references?', 'multiple_choice', '["Two backsights and no occupied point","An occupied (known) point and a backsight to a known point or azimuth","A GPS fix and a benchmark","Two reflectorless surfaces"]'::jsonb, 'An occupied (known) point and a backsight to a known point or azimuth', 'Orientation needs the occupied point (where the instrument stands) and a backsight (a known point or known azimuth) so the software can align the horizontal circle to the job''s coordinate system.', 'easy', 'c100000a-0000-0000-0000-00000000000a', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000009', 'Why do professionals preserve the raw observation file rather than only the reduced coordinate file?', 'multiple_choice', '["Raw files are smaller and load faster","Coordinates cannot be drafted in CAD","Raw data allow the survey to be re-reduced and audited if a control value, HI, or backsight was wrong","The data collector deletes coordinates after upload"]'::jsonb, 'Raw data allow the survey to be re-reduced and audited if a control value, HI, or backsight was wrong', 'Raw observations (angles, distances, HI/HR, backsight) are the technical record. If a control coordinate or backsight is later found wrong, the survey can be reprocessed; a coordinate-only file cannot be corrected.', 'medium', 'c100000a-0000-0000-0000-00000000000a', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000010', 'Assigning consistent feature codes (e.g., EP, TREE, IP) in the field is important mainly because:', 'multiple_choice', '["It increases EDM accuracy","It lets office software build linework automatically and reduces drafting cleanup","It is required to power on the instrument","It changes the coordinate system"]'::jsonb, 'It lets office software build linework automatically and reduces drafting cleanup', 'Feature and line/connect codes let the office software draw linework and attribute points automatically, turning a cloud of shots into a drawing without manual reconstruction.', 'easy', 'c100000a-0000-0000-0000-00000000000a', '400ac37c-79e7-4b0e-ac08-0e51b69706ec', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000011', 'Stakeout (layout) differs from topographic data collection in that:', 'multiple_choice', '["It records where existing features are located","It guides a stake to a predetermined design coordinate — the reverse of topo","It requires no instrument orientation","It cannot report elevations"]'::jsonb, 'It guides a stake to a predetermined design coordinate — the reverse of topo', 'Topo records where points are; stakeout starts from design coordinates and guides a stake to that ground position. Both still require a properly oriented, checked setup.', 'easy', 'c100000a-0000-0000-0000-00000000000a', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000012', 'During grade staking the collector reports ''CUT 0.4 ft'' at a point. This means:', 'multiple_choice', '["The ground is below design and must be filled 0.4 ft","The ground is above design elevation and must be excavated down 0.4 ft","The horizontal position is 0.4 ft off","The prism height is wrong by 0.4 ft"]'::jsonb, 'The ground is above design elevation and must be excavated down 0.4 ft', 'Cut means existing ground is above the design elevation, so 0.4 ft must be excavated. Fill would mean the ground is below design and material must be added.', 'medium', 'c100000a-0000-0000-0000-00000000000a', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000013', 'A free station at N 5000.00, E 5000.00 must stake a design point at N 5120.00, E 5050.00. What is the horizontal distance to stake (to 0.01 ft)?', 'numeric_input', '[]'::jsonb, '130.00', 'D = √(ΔN² + ΔE²) = √(120² + 50²) = √(14400 + 2500) = √16900 = 130.00 ft.', 'medium', 'c100000a-0000-0000-0000-00000000000a', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000014', 'Stakeout will faithfully set production stakes in the wrong location if the backsight orientation is wrong.', 'true_false', '["True","False"]'::jsonb, 'True', 'Stakeout reproduces whatever the orientation and design file say. A wrong backsight, datum, or transposed coordinate is staked precisely in the wrong place — hence the need for an independent check before production staking.', 'easy', 'c100000a-0000-0000-0000-00000000000a', 'ea97aaff-e1e2-408a-8019-f9a1ca7e49f3', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000015', 'Compared with prism measurement, reflectorless (direct-reflex) measurement generally has:', 'multiple_choice', '["Longer range and higher precision","Shorter range and lower precision, but reaches inaccessible points","Identical performance in all conditions","No dependence on surface material"]'::jsonb, 'Shorter range and lower precision, but reaches inaccessible points', 'A diffuse surface returns far less signal than a prism, so reflectorless has shorter range and lower precision, but it can locate points no rodperson could safely reach.', 'easy', 'c100000a-0000-0000-0000-00000000000a', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000016', 'Aiming a reflectorless shot at the corner edge of a building against open sky can produce a wrong distance because:', 'multiple_choice', '["The prism constant changes at edges","The laser footprint can straddle near and far surfaces, returning a blended distance","Edges absorb all the laser light","Zenith angles cannot be read near edges"]'::jsonb, 'The laser footprint can straddle near and far surfaces, returning a blended distance', 'Beam divergence gives the laser a finite footprint. Near an edge that spot can split between the near surface and whatever is behind it, yielding a blended or wrong distance — so critical points should be verified.', 'medium', 'c100000a-0000-0000-0000-00000000000a', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000017', 'Which surface condition gives the strongest, most reliable reflectorless return?', 'multiple_choice', '["A dark, wet, glassy surface at a steep oblique angle","A light-colored flat surface faced squarely (near-perpendicular incidence)","A mirrored or polished metal panel","An edge silhouetted against the sky"]'::jsonb, 'A light-colored flat surface faced squarely (near-perpendicular incidence)', 'Strong returns come from light, flat surfaces at near-normal incidence. Dark/wet/glassy or oblique surfaces weaken the return, and mirrored surfaces can give spurious readings and pose a laser-safety hazard.', 'easy', 'c100000a-0000-0000-0000-00000000000a', '7c3a5f58-fcb3-4105-92cf-4db5055d91ea', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000018', 'In a comma-delimited PNEZD coordinate file, the fields in order are:', 'multiple_choice', '["Point, Northing, Easting, Z (elevation), Description","Prism, North, East, Zenith, Distance","Point, Easting, Northing, Zenith, Date","Position, Name, Elevation, Zone, Datum"]'::jsonb, 'Point, Northing, Easting, Z (elevation), Description', 'PNEZD = Point number, Northing, Easting, Z (elevation), Description. Confirming this order (vs. PENZD) on import prevents silently swapping northing and easting.', 'easy', 'c100000a-0000-0000-0000-00000000000a', 'd8e1362b-c24e-438e-842c-73064b2b656e', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000019', 'Which file is most appropriate when the office needs to re-reduce a survey after discovering a wrong backsight coordinate?', 'multiple_choice', '["The DWG drawing file","The PNEZD coordinate file","The raw data file (e.g., .rw5)","A PDF of the field notes"]'::jsonb, 'The raw data file (e.g., .rw5)', 'The raw file holds the observations (setups, backsights, HI/HR, angles, distances), so it can be reprocessed with the corrected backsight and all dependent points recomputed. A coordinate file cannot be re-reduced.', 'medium', 'c100000a-0000-0000-0000-00000000000a', 'd8e1362b-c24e-438e-842c-73064b2b656e', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000020', 'What does resection (free-stationing) allow a surveyor to do?', 'multiple_choice', '["Measure distance without a prism","Solve the instrument''s own coordinates and orientation by sighting two or more known points, without occupying a monument","Eliminate the need for any control points","Read angles without face-left/face-right observations"]'::jsonb, 'Solve the instrument''s own coordinates and orientation by sighting two or more known points, without occupying a monument', 'Resection sets up at an unknown point and observes known control to compute the station''s coordinates and orientation, letting the crew set up wherever geometry and visibility are best.', 'medium', 'c100000a-0000-0000-0000-00000000000a', '549ace82-2dbd-4aef-84f1-6d48afc86d79', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000021', 'A resection is strongest (best conditioned) when the known control points sighted are:', 'multiple_choice', '["Nearly in a straight line with the instrument","Clustered within a narrow angle","Well distributed with good intersection angles, ideally three or more for redundancy","All at the same distance and direction"]'::jsonb, 'Well distributed with good intersection angles, ideally three or more for redundancy', 'Well-distributed points with strong intersection angles give a robust solution, and three or more provide a residual check. Collinear or narrowly clustered points produce a weak, ill-conditioned result.', 'medium', 'c100000a-0000-0000-0000-00000000000a', '549ace82-2dbd-4aef-84f1-6d48afc86d79', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee1030-0000-0000-0000-000000000022', 'In radial topography, a point is located from an oriented setup by:', 'multiple_choice', '["Two distances from two stations","A single horizontal direction and slope distance, radiated to a coordinate","Differential leveling only","A GPS observation at each point"]'::jsonb, 'A single horizontal direction and slope distance, radiated to a coordinate', 'Radial topo locates each feature with one angle-and-distance shot; the processor radiates a coordinate as N = N₁ + D·cos(Az), E = E₁ + D·sin(Az). This is the everyday total-station method.', 'easy', 'c100000a-0000-0000-0000-00000000000a', '549ace82-2dbd-4aef-84f1-6d48afc86d79', ARRAY['buildout','module-10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1060-0000-0000-0000-000000000001', 'From an oriented total-station setup at point A (N = {{n1}}.00 ft, E = {{e1}}.00 ft), a radial shot to point P has a horizontal distance of {{dist}}.00 ft at an azimuth of {{az}}°. What is the NORTHING of point P (in feet)?', 'numeric_input', '[]'::jsonb, '0', 'The forward (radial) computation gives Nₚ = N₁ + D·cos(Az) = {{n1}}.00 + {{dist}}·cos({{az}}°) = {{n2:f2}} ft.', 'medium', 'c100000a-0000-0000-0000-00000000000a', NULL, ARRAY['buildout','module-10','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1050-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1060-0000-0000-0000-000000000002', 'A total station measures a slope distance of {{slope}}.00 ft to a prism at a zenith angle of {{zenith}}°00''. What is the HORIZONTAL distance (in feet)?', 'numeric_input', '[]'::jsonb, '0', 'Reducing slope to horizontal: H = S·sin(Z) = {{slope}}.00 × sin({{zenith}}°) = {{horiz:f2}} ft. (Zenith is measured from vertical, so a level sight is 90°.)', 'easy', 'c100000a-0000-0000-0000-00000000000a', NULL, ARRAY['buildout','module-10','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1050-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee1060-0000-0000-0000-000000000003', 'An instrument is set up at a point of elevation {{elevA}}.00 ft with a height of instrument HI = {{hi}}.0 ft (in tenths). It observes a prism (HR = {{hr}}.0 ft) at slope distance {{slope}}.00 ft and zenith angle {{zenith}}°00''. What is the ELEVATION of the observed point (in feet)? Use V = HI + S·cos(Z) − HR added to the setup elevation.', 'numeric_input', '[]'::jsonb, '0', 'Trigonometric elevation: Elev = Elevₐ + HI + S·cos(Z) − HR = {{elevA}}.00 + {{hi}}.0 + {{slope}}·cos({{zenith}}°) − {{hr}}.0 = {{elevB:f2}} ft. When Z > 90° the cosine is negative (sight downhill).', 'medium', 'c100000a-0000-0000-0000-00000000000a', NULL, ARRAY['buildout','module-10','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee1050-0000-0000-0000-000000000003', 0.05);
