DELETE FROM problem_templates WHERE module_id='c100000a-0000-0000-0000-00000000000a' AND created_by='buildout:m10';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['A total station integrates an electronic theodolite (angles), an EDM (distances), and an onboard processor/data collector in one instrument.','A correct setup means the instrument is centered over the mark and the vertical axis is truly vertical (leveled); both must be true simultaneously.','Height of instrument (HI) is measured to the trunnion axis and height of reflector (HR) to the prism center; both are required for trigonometric elevations.']::text[], learning_objectives=ARRAY['Identify the principal components of a total station and explain the function of each.','Set up and orient a total station correctly over a point using centering and leveling.','Measure and apply the height of instrument (HI) and height of reflector (HR) for elevation work.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='15139528-33df-4856-94bb-dff559fa6688';
DELETE FROM lesson_blocks WHERE lesson_id='15139528-33df-4856-94bb-dff559fa6688';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Electronic angle encoders read the position of a graduated circle electronically, eliminating manual micrometer reading and reducing reading blunders.','An EDM measures slope distance by comparing the phase of returned modulated light (phase method) or timing a pulse''s round trip (pulse method).','Horizontal distance is recovered from slope distance with H = S·sin(Z), where Z is the zenith angle, after applying atmospheric and instrument corrections.']::text[], learning_objectives=ARRAY['Explain how electronic angle encoders measure horizontal and vertical angles.','Describe how an EDM measures distance using phase comparison or pulse time-of-flight.','Reduce a slope distance to a horizontal distance using the zenith angle.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83';
DELETE FROM lesson_blocks WHERE lesson_id='ff0b9ea1-bbb1-47f0-a2c1-e197d00b2c83';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['The data collector runs field software that controls the instrument, stores observations, and computes coordinates live, replacing the paper field book.','Every setup is oriented by occupying a known point and backsighting another known point (or a known azimuth) before any sideshots are taken.','Field software stores both reduced coordinates and the underlying raw data (angles, distances, HI/HR) so the work can be re-reduced and audited.']::text[], learning_objectives=ARRAY['Describe the role of a data collector and field software in a total-station workflow.','Explain how a job is set up: occupy, backsight, orientation, and point coding.','Distinguish raw observation data from reduced coordinate data and explain why both are kept.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='400ac37c-79e7-4b0e-ac08-0e51b69706ec';
DELETE FROM lesson_blocks WHERE lesson_id='400ac37c-79e7-4b0e-ac08-0e51b69706ec';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Stakeout reverses topo: instead of recording where a point is, you guide a rod to where a design point should be.','The data collector computes the inverse from the instrument to each design point and directs the rodperson in/out and left/right, then reports cut or fill.','An oriented, checked setup and a verified design point list are prerequisites; a bad backsight stakes everything in the wrong place.']::text[], learning_objectives=ARRAY['Explain the stakeout (layout) workflow: loading design points and guiding to position.','Interpret the data collector''s go/come, left/right, and cut/fill guidance.','Compute the bearing/azimuth and distance from a setup to a design point (inverse).']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='ea97aaff-e1e2-408a-8019-f9a1ca7e49f3';
DELETE FROM lesson_blocks WHERE lesson_id='ea97aaff-e1e2-408a-8019-f9a1ca7e49f3';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Reflectorless (direct-reflex) EDM measures to a surface using the light scattered back from the material, so no prism is needed.','It is ideal for inaccessible or unsafe points — building faces, cliff edges, traffic areas — but is less precise and range-limited compared with prism work.','Beam divergence, oblique surfaces, edges, and dark/wet materials degrade reflectorless accuracy; aim at the true point and verify critical shots.']::text[], learning_objectives=ARRAY['Explain how reflectorless (direct-reflex) EDM measures distance to a surface without a prism.','Identify appropriate uses and the limitations/error sources of reflectorless measurement.','Apply safe and accurate practices for reflectorless shots on faces and edges.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='7c3a5f58-fcb3-4105-92cf-4db5055d91ea';
DELETE FROM lesson_blocks WHERE lesson_id='7c3a5f58-fcb3-4105-92cf-4db5055d91ea';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=30, key_takeaways=ARRAY['Two file families move from field to office: coordinate files (point lists) and raw data files (the observations).','Raw files (e.g., .rw5) let the office re-reduce the survey, while coordinate files (e.g., comma-delimited PNEZD) feed the drawing/COGO directly.','Reliable transfer, consistent point/feature coding, and archived raw data are what make the work efficient and defensible.']::text[], learning_objectives=ARRAY['Distinguish coordinate files from raw data files and describe common formats.','Explain the field-to-office workflow: download, import, re-reduce, and draft.','Apply data-management practices that preserve a defensible record of the survey.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='d8e1362b-c24e-438e-842c-73064b2b656e';
DELETE FROM lesson_blocks WHERE lesson_id='d8e1362b-c24e-438e-842c-73064b2b656e';
UPDATE learning_lessons SET content_migrated=true, estimated_minutes=35, key_takeaways=ARRAY['Collimation, trunnion-axis tilt, and vertical-index errors are checked by calibration; observing face left/face right cancels many of them in the field.','Resection (free-stationing) places the instrument anywhere and solves its coordinates by sighting two or more known points — no setup over a known mark required.','Radial topo locates many points by single angle-and-distance shots from one oriented setup; careful care and periodic calibration keep results trustworthy.']::text[], learning_objectives=ARRAY['Identify the instrument errors checked by calibration and how field procedures remove them.','Describe resection/free-stationing and radial topo as field methods enabled by total stations.','Apply routine care, field checks, and maintenance to keep a total station in tolerance.']::text[], status='published', is_published=true, review_status='approved', updated_at=now() WHERE id='549ace82-2dbd-4aef-84f1-6d48afc86d79';
DELETE FROM lesson_blocks WHERE lesson_id='549ace82-2dbd-4aef-84f1-6d48afc86d79';
  'eeee1050-0000-0000-0000-000000000001', 'Radial coordinate from a setup (forward computation)', 'Radial coordinate from a setup (forward computation)', 'Total Stations and Electronic Surveying — Coordinate Geometry', 'Forward / radial coordinate', 'numeric_input', 'medium', 'From an oriented total-station setup at point A (N = {{n1}}.00 ft, E = {{e1}}.00 ft), a radial shot to point P has a horizontal distance of {{dist}}.00 ft at an azimuth of {{az}}°. What is the NORTHING of point P (in feet)?', 'n1 + dist*cos(toRad(az))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"n1","type":"integer","min":4000,"max":6000},{"name":"e1","type":"integer","min":4000,"max":6000},{"name":"dist","type":"integer","min":100,"max":500},{"name":"az","type":"integer","min":20,"max":70}]'::jsonb, '[{"name":"n2","formula":"n1 + dist*cos(toRad(az))"}]'::jsonb, '[{"step_number":1,"title":"Northing departure","formula":"ΔN = D·cos(Az)","calculation_template":"{{dist}} × cos({{az}}°)"},{"step_number":2,"title":"Add to setup northing","result_template":"{{n1}}.00 + {{dist}}·cos({{az}}°) = {{n2:f2}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The forward (radial) computation gives Nₚ = N₁ + D·cos(Az) = {{n1}}.00 + {{dist}}·cos({{az}}°) = {{n2:f2}} ft.', 'c100000a-0000-0000-0000-00000000000a', ARRAY['buildout','module-10','practice']::text[], true, 'buildout:m10');
  'eeee1050-0000-0000-0000-000000000002', 'Horizontal distance from slope distance and zenith angle', 'Horizontal distance from slope distance and zenith angle', 'Total Stations and Electronic Surveying — Distance Reduction', 'Slope-to-horizontal reduction', 'numeric_input', 'easy', 'A total station measures a slope distance of {{slope}}.00 ft to a prism at a zenith angle of {{zenith}}°00''. What is the HORIZONTAL distance (in feet)?', 'slope*sin(toRad(zenith))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"slope","type":"integer","min":150,"max":600},{"name":"zenith","type":"integer","min":82,"max":98}]'::jsonb, '[{"name":"horiz","formula":"slope*sin(toRad(zenith))"}]'::jsonb, '[{"step_number":1,"title":"Apply H = S·sin(Z)","formula":"H = S·sin(Z)","calculation_template":"{{slope}} × sin({{zenith}}°)"},{"step_number":2,"title":"Horizontal distance","result_template":"H = {{horiz:f2}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Reducing slope to horizontal: H = S·sin(Z) = {{slope}}.00 × sin({{zenith}}°) = {{horiz:f2}} ft. (Zenith is measured from vertical, so a level sight is 90°.)', 'c100000a-0000-0000-0000-00000000000a', ARRAY['buildout','module-10','practice']::text[], true, 'buildout:m10');
  'eeee1050-0000-0000-0000-000000000003', 'Trigonometric elevation of a point from a setup', 'Trigonometric elevation of a point from a setup', 'Total Stations and Electronic Surveying — Trigonometric Leveling', 'Elevation by total station', 'numeric_input', 'medium', 'An instrument is set up at a point of elevation {{elevA}}.00 ft with a height of instrument HI = {{hi}}.0 ft (in tenths). It observes a prism (HR = {{hr}}.0 ft) at slope distance {{slope}}.00 ft and zenith angle {{zenith}}°00''. What is the ELEVATION of the observed point (in feet)? Use V = HI + S·cos(Z) − HR added to the setup elevation.', 'elevA + hi + slope*cos(toRad(zenith)) - hr', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"elevA","type":"integer","min":500,"max":900},{"name":"hi","type":"integer","min":4,"max":6},{"name":"hr","type":"integer","min":4,"max":6},{"name":"slope","type":"integer","min":150,"max":400},{"name":"zenith","type":"integer","min":80,"max":100}]'::jsonb, '[{"name":"elevB","formula":"elevA + hi + slope*cos(toRad(zenith)) - hr"}]'::jsonb, '[{"step_number":1,"title":"Vertical component","formula":"V = S·cos(Z)","calculation_template":"{{slope}} × cos({{zenith}}°)"},{"step_number":2,"title":"Combine with HI and HR","formula":"Elev = Elevₐ + HI + V − HR","calculation_template":"{{elevA}}.00 + {{hi}}.0 + {{slope}}·cos({{zenith}}°) − {{hr}}.0"},{"step_number":3,"title":"Elevation of point","result_template":"= {{elevB:f2}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Trigonometric elevation: Elev = Elevₐ + HI + S·cos(Z) − HR = {{elevA}}.00 + {{hi}}.0 + {{slope}}·cos({{zenith}}°) − {{hr}}.0 = {{elevB:f2}} ft. When Z > 90° the cosine is negative (sight downhill).', 'c100000a-0000-0000-0000-00000000000a', ARRAY['buildout','module-10','practice']::text[], true, 'buildout:m10');
COMMIT;
SELECT 'm10 Total Stations and Electronic Surveying: ' || (SELECT count(*) FROM lesson_blocks lb JOIN learning_lessons l ON l.id=lb.lesson_id WHERE l.module_id='c100000a-0000-0000-0000-00000000000a') || ' blocks.' AS status;